function generateValidNumbers(n) {
  const validDigits = ['0', '1', '6', '8', '9'];
  const rotationMap = { '0': '0', '1': '1', '6': '9', '8': '8', '9': '6' };

  // Helper function to check if a number is valid when rotated 180 degrees
  function isValidRotated(number) {
    let rotatedNumber = '';
    for (let i = number.length - 1; i >= 0; i--) {
      const digit = number[i];
      if (!rotationMap[digit]) return false;
      rotatedNumber += rotationMap[digit];
    }
    return rotatedNumber === number;
  }

  // Generate all combinations of n digits using valid digits
  function generateCombinations(arr, len) {
    if (len === 1) return arr;
    const combinations = [];
    arr.forEach((digit) => {
      const subCombinations = generateCombinations(arr, len - 1);
      subCombinations.forEach((subComb) => {
        combinations.push(digit + subComb);
      });
    });
    return combinations;
  }

  const allCombinations = generateCombinations(validDigits, n);
  const validNumbers = allCombinations.filter(isValidRotated);

  return validNumbers;
}

// Example usage
for (let n = 1; n <= 3; n++) {
  const validNumbers = generateValidNumbers(n);
  console.log(`Count of valid ${n}-digit numbers that look the same when rotated 180 degrees: ${validNumbers.length}`);
  console.log("Valid numbers:", validNumbers);
}
